  function getStanOfflineResponse(q) {
    const lq = q.toLowerCase();

    // Wallet recovery
    if (lq.includes("recover") || lq.includes("lost wallet") || lq.includes("lost access") || lq.includes("forgot password") || lq.includes("lost seed") || lq.includes("seed phrase") || lq.includes("private key") || lq.includes("restore wallet")) {
      return `Stan here — let's work through this carefully.\n\n**Wallet recovery options depend on what you still have:**\n\n1. **You have your seed phrase (12 or 24 words)** — you can fully restore your wallet. Download the official wallet app (e.g. Electrum for Bitcoin, or your hardware wallet's companion app), select "Restore from seed" and enter your words in the exact order. Your funds will reappear once it syncs.\n\n2. **You have your private key** — import it into a compatible wallet. In Electrum: Wallet → Import → paste your private key. This gives full access.\n\n3. **You have the wallet file (.dat or similar)** — for Bitcoin Core, copy the wallet.dat file into the Bitcoin Core data directory and resync. For other wallets, check their specific restore documentation.\n\n4. **You have nothing (no seed, no key, no file)** — unfortunately there is no way to recover a crypto wallet without at least one of the above. Anyone claiming they can recover it for a fee is almost certainly a scam. Do not pay anyone.\n\n**What do you still have access to?** Tell me and I'll walk you through the exact steps.`;
    }

    // Scam / fraud
    if (lq.includes("scam") || lq.includes("fraud") || lq.includes("hack") || lq.includes("stolen") || lq.includes("phish")) {
      return `Stan here — this is serious, let's act fast.\n\n**If your wallet or exchange account has been compromised:**\n\n1. **Move funds immediately** — if you still have access, send remaining funds to a new wallet you control right now.\n2. **Revoke permissions** — if DeFi was involved, go to revoke.cash and revoke any suspicious token approvals.\n3. **Secure your accounts** — change passwords and enable 2FA on all connected accounts (email, exchange, etc.).\n4. **Do not interact with the attacker** — do not send more funds trying to "recover" lost crypto. This is always a secondary scam.\n5. **Report it** — report to Action Fraud (UK: actionfraud.police.uk) or IC3 (US: ic3.gov). Also report to the exchange if it was exchange-related.\n\n**Crypto transactions are irreversible** — once sent, funds cannot be recalled. The focus now is securing what remains.\n\nWhat happened exactly? I'll help you with next steps.`;
    }

    // Stuck / pending transaction
    if (lq.includes("stuck") || lq.includes("pending") || lq.includes("transaction") || lq.includes("unconfirmed") || lq.includes("not arrived") || lq.includes("not received")) {
      return `Stan here — let's get this sorted.\n\n**Stuck or pending Bitcoin transaction:**\n\n1. **Check the mempool** — go to mempool.space and paste your transaction ID (TXID). This shows exactly where your transaction is and its current fee rate.\n2. **Low fee?** — if the fee is too low for current network congestion, it will sit in the mempool until confirmed or dropped (usually after 2 weeks).\n3. **RBF (Replace-by-Fee)** — if your wallet supports it (Electrum does), you can bump the fee on an unconfirmed transaction. Go to Transactions → right-click → Increase Fee.\n4. **CPFP (Child Pays for Parent)** — if you're the recipient, you can create a new transaction spending the unconfirmed output with a higher fee to pull both through.\n5. **Exchange deposits** — if sending to an exchange, most require 1-3 confirmations. Just wait — it will arrive once confirmed.\n\nPaste your TXID and I can tell you exactly what's happening with it.`;
    }

    // Hardware wallet / cold storage
    if (lq.includes("ledger") || lq.includes("trezor") || lq.includes("cold storage") || lq.includes("hardware wallet") || lq.includes("coldcard")) {
      return `Stan here — let's get this sorted.\n\n**Hardware wallet support:**\n\n1. **Device not recognised** — try a different USB cable (many cables are charge-only, not data). Try a different USB port. Restart Ledger Live or Trezor Suite.\n2. **Ledger "device is locked"** — enter your PIN on the device itself, not the app.\n3. **Firmware update issues** — always update via the official app only. If the update fails midway, reconnect and retry — the device recovers automatically.\n4. **Lost PIN** — if you have your 24-word seed phrase, do a factory reset and restore. Without the seed phrase, the device cannot be recovered.\n5. **Setting up a new device** — never buy a hardware wallet second-hand. Only buy from the official manufacturer. The seed phrase is generated on-device and must never be entered on a computer.\n\n**What model do you have and what's the specific issue?**`;
    }

    // Exchange problems
    if (lq.includes("exchange") || lq.includes("binance") || lq.includes("coinbase") || lq.includes("kraken") || lq.includes("withdraw") || lq.includes("deposit") || lq.includes("kyc") || lq.includes("verify") || lq.includes("account")) {
      return `Stan here — let's work through this.\n\n**Common exchange issues:**\n\n1. **Withdrawal blocked / KYC required** — most exchanges require identity verification for withdrawals. Complete KYC in your account settings. Use clear, well-lit photos of your ID.\n2. **Deposit not showing** — check the blockchain explorer for your deposit address. If the transaction is confirmed on-chain but not in your exchange account, contact exchange support with your TXID.\n3. **Wrong network sent** — if you sent on the wrong network (e.g. sent BNB chain instead of Ethereum), contact the exchange support immediately. Some exchanges can recover cross-chain deposits for a fee.\n4. **Account locked / 2FA issues** — use the exchange's account recovery process. You'll need to verify your identity. Have your ID and proof of account ownership ready.\n5. **Suspicious activity freeze** — exchanges freeze accounts for security reviews. Contact support, respond honestly and provide requested documents.\n\n**Which exchange and what exactly is happening?**`;
    }

    // Mining - overheating
    if (lq.includes("heat") || lq.includes("hot") || lq.includes("temperature") || lq.includes("overheat")) {
      return `Stan here — let's get this sorted.\n\nOverheating mining machine troubleshooting:\n\n1. **Check ambient temperature** — your mining room should be below 35°C (95°F). Ideal is 15-25°C.\n2. **Inspect fans** — spin each fan manually. Replace any that are stiff or noisy.\n3. **Clean dust filters** — use compressed air to blow out all heatsinks and PCBs. Do this monthly.\n4. **Check thermal paste** — on hash boards, thermal paste degrades over time. Re-applying can drop temps 15-20°C.\n5. **Improve airflow** — miners need clear input AND output airflow. No hot air recirculation.\n6. **Reduce overclock** — dial back frequency in the miner's web interface.\n\nIf temps exceed 85°C on hash boards, shut down immediately to prevent damage.`;
    }

    // Mining - hash rate
    if (lq.includes("hash") || lq.includes("hashrate") || lq.includes("hash rate")) {
      return `Stan here — let's get this sorted.\n\nLow hash rate troubleshooting:\n\n1. **Check hash board status** — access your miner's web interface (usually 192.168.1.X). Look for red or missing hash boards.\n2. **Restart the miner** — a simple power cycle fixes many temporary issues.\n3. **Check pool settings** — verify your pool URL, worker name and password are correct.\n4. **Inspect cables** — data cables between control board and hash boards can work loose. Reseat all internal connectors.\n5. **Temperature check** — if running hot (>80°C), hash rate will throttle. Fix cooling first.\n6. **Firmware update** — check manufacturer website for latest stable firmware.\n\nWhat is your exact miner model?`;
    }

    // Mining - pool connection
    if (lq.includes("pool") || lq.includes("stratum") || (lq.includes("connect") && lq.includes("min"))) {
      return `Stan here — let's get this sorted.\n\nPool connection troubleshooting:\n\n1. **Verify pool URL** — check your pool's official website for current stratum URLs.\n2. **Try backup pools** — configure 3 pool URLs in your miner.\n3. **Check firewall/router** — mining pools use ports 3333, 3334, 4444, 14444. Ensure these aren't blocked.\n4. **Worker name format** — usually: walletAddress.workerName or username.workerName.\n5. **Popular pools**: Braiins (braiins.com), F2Pool (f2pool.com), Foundry USA (foundrydigital.com).\n\nWhat pool and miner are you using?`;
    }

    // Firmware
    if (lq.includes("firmware") || lq.includes("update") || lq.includes("flash")) {
      return `Stan here — let's get this sorted.\n\nFor firmware updates:\n\n1. **Always use the official manufacturer site** — never third party sources.\n2. **Backup your config** — export your pool settings before updating.\n3. **Don't interrupt the flash** — keep power stable throughout. A failed flash mid-way can brick the unit.\n4. **Antminer**: download from bitmain.com, flash via web interface under System → Upgrade.\n5. **Bitaxe**: use AxeOS web interface or flash via USB with official tools from GitHub.\n\nWhich miner model are you updating?`;
    }

    // Generic / unknown
    return `Stan here — let's get this sorted.\n\nI can help with:\n\n• **Wallet issues** — lost access, seed phrase recovery, hardware wallets\n• **Transactions** — stuck/pending, wrong address, deposits not arriving\n• **Exchange problems** — withdrawals, KYC, account access\n• **Mining hardware** — hash rate, overheating, pool connections, firmware\n• **Crypto security** — scams, account protection, best practices\n\nCould you describe your problem in a bit more detail? The more you tell me, the more accurately I can help.`;
  }

